async (page) => {
  // Chop rotation: click nearby oak trees, wait 8s each, rotate through 3 trees
  const trees = [{x:187,y:151},{x:195,y:153},{x:186,y:158}];
  for (let i = 0; i < 9; i++) {
    const tree = trees[i % trees.length];
    await page.evaluate(({x,y}) => window.__clickTile(x,y), tree);
    await page.waitForTimeout(8000);
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed = JSON.parse(state);
    const logs = parsed.inventory.find(i => i.key === 'logs');
    const logCount = logs ? logs.count : 0;
    if (logCount >= 10) break;
  }
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({pos: parsed.player_position, inv: parsed.inventory, skills: parsed.skills});
}

