async (page) => {
  // Stay near (186,158) and chop, waiting 10s between each. Tree respawns every 25s.
  // Also try nearby trees when this one is depleted
  const primaryTree = {x:186, y:158};
  const altTree1 = {x:186, y:165};
  const altTree2 = {x:187, y:151};

  for (let i = 0; i < 15; i++) {
    // Click primary tree
    await page.evaluate(({x,y}) => window.__clickTile(x,y), primaryTree);
    await page.waitForTimeout(10000);

    // Check log count
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed = JSON.parse(state);
    const totalLogs = parsed.inventory.filter(item => item.key === 'logs').reduce((s, item) => s + item.count, 0);
    if (totalLogs >= 10) break;

    // Try alt tree every other round
    if (i % 2 === 1) {
      await page.evaluate(({x,y}) => window.__clickTile(x,y), altTree1);
      await page.waitForTimeout(10000);
    }
    const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed2 = JSON.parse(state2);
    const totalLogs2 = parsed2.inventory.filter(item => item.key === 'logs').reduce((s, item) => s + item.count, 0);
    if (totalLogs2 >= 10) break;
  }

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const totalLogs = parsed.inventory.filter(item => item.key === 'logs').reduce((s, item) => s + item.count, 0);
  return JSON.stringify({pos: parsed.player_position, totalLogs, skills: parsed.skills});
}

