async (page) => {
  // Attack nearby Rats to build Strength. Use __attackMob to find and fight them.
  let totalKills = 0;
  for (let i = 0; i < 20; i++) {
    const result = await page.evaluate((name) => JSON.stringify(window.__attackMob(name)), 'Rat');
    const res = JSON.parse(result);
    if (res.error) {
      // No rat visible, move a bit
      await page.evaluate(({x,y}) => window.__moveTo(x,y), {x: 191, y: 158});
      await page.waitForTimeout(3000);
      continue;
    }
    // Wait for mob to die
    await page.waitForTimeout(7000);
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed = JSON.parse(state);
    const str = parsed.skills.Strength;
    if (str && str.level >= 10) break;
    totalKills++;
  }
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({pos: parsed.player_position, kills: totalKills, skills: parsed.skills, hp: parsed.player_stats.hp + '/' + parsed.player_stats.max_hp});
}

