async (page) => {
  await page.waitForTimeout(5000);
  const bubbaId = '1-44010828';
  // Talk to Bubba to get crab achievement quest
  for (let i = 0; i < 6; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), bubbaId);
    await page.waitForTimeout(1500);
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed = JSON.parse(state);
    if (parsed.ui_state.quest_panel_visible) {
      await page.evaluate(() => document.getElementById('quest-button').click());
      await page.waitForTimeout(1000);
      break;
    }
    if (!parsed.ui_state.npc_dialogue) break;
  }
  // Also try direct accept
  const result = await page.evaluate((key) => JSON.stringify(window.__acceptQuest(key)), 'crabproblem');
  await page.waitForTimeout(500);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({pos: parsed.player_position, quests: parsed.quests, achievements: parsed.achievements, acceptResult: JSON.parse(result)});
}

async (page) => {
  let crabKills = 0;
  for (let i = 0; i < 15; i++) {
    const result = await page.evaluate((name) => JSON.stringify(window.__attackMob(name)), 'Crab');
    const res = JSON.parse(result);
    if (res.error) {
      await page.evaluate(({x,y}) => window.__moveTo(x,y), {x: 130, y: 225});
      await page.waitForTimeout(3000);
      continue;
    }
    await page.waitForTimeout(6000); // Crabs have 15 HP, die fast
    crabKills++;
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed = JSON.parse(state);
    // Check achievements
    const crabAch = parsed.achievements.find(a => a.key === 'crabproblem');
    if (crabAch && crabAch.finished) break;
    if (crabKills >= 10) break;
  }
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({crabKills, pos: parsed.player_position, achievements: parsed.achievements, skills: {str: parsed.skills.Strength, def: parsed.skills.Defense}});
}

