async (page) => {
  // Move directly adjacent to Bubba
  await page.evaluate(({x,y}) => window.__moveTo(x,y), {x: 120, y: 231});
  await page.waitForTimeout(3000);

  const bubbaId = '1-44010828';
  let dialogues = [];
  for (let i = 0; i < 8; i++) {
    const result = await page.evaluate((id) => window.__talkToNPC(id), bubbaId);
    await page.waitForTimeout(1500);
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const parsed = JSON.parse(state);
    if (parsed.ui_state.npc_dialogue) dialogues.push(parsed.ui_state.npc_dialogue);
    if (parsed.ui_state.quest_panel_visible) {
      await page.evaluate(() => document.getElementById('quest-button').click());
      await page.waitForTimeout(1000);
      break;
    }
    if (!parsed.ui_state.npc_dialogue && i > 1) break;
  }
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({pos: parsed.player_position, dialogues, achievements: parsed.achievements, quests: parsed.quests});
}
